#!/usr/bin/env python3
import pathlib, json, base64, subprocess, sys

FILES_B64 = {
  "Cargo.toml": "",
  ".gitignore": "",
  "src/lib.rs": "",
  "src/error.rs": "",
  "src/graph/mod.rs": "",
  "src/models/mod.rs": "",
  "src/solver/mod.rs": "",
  "src/likelihood/mod.rs": "",
  "src/problem/mod.rs": "",
  "src/optimizer/mod.rs": "",
  "src/integrator/mod.rs": "",
  "src/density/mod.rs": "",
  "src/marginal/mod.rs": "",
  "src/inference/mod.rs": "",
  "benches/cholesky_bench.rs": "",
  ".github/workflows/ci.yml": "",
  "tests/fixtures/README.md": ""
}

def main():
    print("\nCreando proyecto rust-inla...\n")
    files = {k: base64.b64decode(v).decode("utf-8") for k, v in FILES_B64.items()}
    for path_str, content in files.items():
        p = pathlib.Path(path_str)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")
        print(f"  ok  {path_str}")
    print(f"\n{len(files)} archivos creados.")
    print("\ncargo build (2-3 min la primera vez)...\n")
    r = subprocess.run(["cargo", "build"], capture_output=True, text=True)
    if r.returncode != 0:
        print("ERROR:")
        print(r.stderr[-3000:])
        sys.exit(1)
    print("  cargo build: OK")
    print("\ncargo test...\n")
    r2 = subprocess.run(["cargo", "test"], capture_output=True, text=True)
    if r2.returncode != 0:
        print(r2.stdout[-2000:])
        sys.exit(1)
    print("  cargo test: OK")
    for line in r2.stdout.splitlines():
        if any(x in line for x in ["test result", "running", "ok"]):
            print(f"     {line}")
    print("\nListo. Ejecuta:")
    print("  git add .")
    print('  git commit -m "feat: scaffold inicial"')
    print("  git push")

if __name__ == "__main__":
    main()
